  }

  /**
   * Phase 6: Capability 헬퍼 함수들
   */
  private capabilityCovers(caller: Capability, callee: Capability): boolean {
    if (caller.cap !== callee.cap) return false
    if (!callee.arg) return true // callee가 경로 무관하면 OK
    if (!caller.arg) return false

    // Path: /tmp → /tmp/file.txt OK, /tmp → /etc NG
    if (caller.cap === "read_file" || caller.cap === "write_file") {
      return this.pathIsUnder(callee.arg, caller.arg)
    }

    // Network: api.openai.com → api.openai.com OK, *.openai.com → sub.openai.com OK
    if (caller.cap === "network") {
      return this.hostMatches(callee.arg, caller.arg)
    }

    return caller.arg === callee.arg
  }

  private pathIsUnder(target: string, allowedPrefix: string): boolean {
    // ".." 즉시 거부
    if (target.includes("..")) return false
    const normalized = target.replace(/\/+/g, "/").replace(/\/$/, "")
    const prefix = allowedPrefix.replace(/\/+/g, "/").replace(/\/$/, "")
    return normalized === prefix || normalized.startsWith(prefix + "/")
  }

  private hostMatches(target: string, pattern: string): boolean {
    if (pattern === target) return true
    if (pattern.startsWith("*.")) {
      const base = pattern.slice(2)
      return (
        target.endsWith("." + base) &&
        !target.slice(0, -base.length - 1).includes(".")
      )
    }
    return false
  }
}

